import java.util.ArrayList;
import java.util.Collections;

public static long[][] solve(long[][] grid, long x, long y, long k) {
    long[][] newGrid = new long[grid.length][grid[0].length];
    for (int i = 0; i < grid.length; i++) {
        for (int j = 0; j < grid[i].length; j++) {
            newGrid[i][j] = grid[i][j];
        }
    }

    ArrayList<long[]> submatrix = new ArrayList<>();
    for (int i = 0; i < k; i++) {
        long[] row = new long[k];
        for (int j = 0; j < k; j++) {
            row[j] = newGrid[(int)x + i][(int)y + j];
        }
        submatrix.add(row);
    }

    Collections.reverse(submatrix);

    for (int i = 0; i < k; i++) {
        long[] reversedRow = submatrix.get(i);
        for (int j = 0; j < k; j++) {
            newGrid[(int)x + i][(int)y + j] = reversedRow[j];
        }
    }

    return newGrid;
}
