import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class Solution {
    public static long[][] solve(long[][] grid, long x, long y, long k) {
        int m = grid.length;
        int n = grid[0].length;
        long[][] newGrid = new long[m][n];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                newGrid[i][j] = grid[i][j];
            }
        }

        List<long[]> submatrix = new ArrayList<>();
        for (int i = 0; i < k; i++) {
            long[] row = new long[k];
            for (int j = 0; j < k; j++) {
                row[j] = newGrid[(int)x + i][(int)y + j];
            }
            submatrix.add(row);
        }

        Collections.reverse(submatrix);

        for (int i = 0; i < k; i++) {
            long[] reversedRow = submatrix.get(i);
            for (int j = 0; j < k; j++) {
                newGrid[(int)x + i][(int)y + j] = reversedRow[j];
            }
        }

        return newGrid;
    }
}
```

